#include <bits/stdc++.h>
using namespace std;
struct Node{
	int a,b,c;
}f[55];
int n,m;
long long dp[55][100005];
bool cmp(Node x,Node y){
	return 1LL*x.c*y.b<1LL*y.c*x.b;
}
int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++)
    	scanf("%d",&f[i].a);
    for(int i=1;i<=n;i++)
    	scanf("%d",&f[i].b);
    for(int i=1;i<=n;i++)
    	scanf("%d",&f[i].c);
    sort(f+1,f+n+1,cmp);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			if(j>=f[i].c)
				dp[i][j]=max(dp[i-1][j],dp[i-1][j-f[i].c]+f[i].a-1LL*j*f[i].b);
			else
				dp[i][j]=dp[i-1][j];
	long long ans=0;
	for(int i=1;i<=m;i++)
		ans=max(ans,dp[n][i]);
	printf("%lld",ans);
	return 0;
}
